VALUES
  ('real-estate-moex-01104', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲於民國102年1月1日向乙借新臺幣10萬元，約定同年6月30日清償，並由丙於其期限內擔任 保證人。下列敘述何者正確？', '["清償期屆滿，乙允許甲延期清償時，應得丙之同意，否則丙不負保證責任", "丙得隨時通知乙終止保證契約，並於通知到達乙後，不負保證責任", "清償期屆滿後，丙應定一個月以上之期限催告乙向甲請求，丙始能免責", "丙得隨時通知甲終止保證契約，並於通知到達甲後，不負保證責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01105', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙、丙三人共有一筆A地，應有部分各三分之一。下列敘述何者錯誤？', '["甲、乙二人得在未經丙同意的情況下，將A地出售與丁建設公司", "甲、乙二人得在未經丙同意的情況下，將A地出租與戊使用", "甲得在未經乙、丙同意的情況下，將其A地的應有部分設定抵押權與庚銀行", "甲、乙、丙三人經裁判分割A地時，須待分割登記完成時，才各自取得單獨所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01106', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲承攬乙建設公司之營造工程，在執行承攬事項時，因過失致路人丙受到傷害。下列敘述何者正確？', '["乙建設公司如非於定作或指示有過失，即不負損害賠償責任", "乙建設公司雖非於定作或指示有過失，但應與甲連帶負損害賠償責任", "乙建設公司賠償丙之損害後，對甲有內部求償權", "乙建設公司應單獨對丙負損害賠償責任，對甲無內部求償權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01107', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲男與乙女已經訂婚，而且同居，雖尚未結婚，但感情非常好。甲男某日外出工作，遭無照駕駛之 丙喝酒闖紅燈撞擊，當場死亡。下列敘述何者正確？', '["因乙女與甲男有訂婚之關係，故乙女得請求丙賠償慰撫金", "因乙女與甲男已經同居，故乙女得請求丙賠償慰撫金", "因乙女與甲男感情非常好，故乙女得請求丙賠償慰撫金", "因乙女與甲男尚未結婚，故乙女不得請求丙賠償慰撫金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01108', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲房東將其所有A屋出租給乙房客，嗣後甲因財務問題將A屋出售與丙。下列敘述何者正確？', '["丙擁有A屋的所有權，所以丙可以要求乙房客搬遷", "若甲、乙之間的房屋租賃契約未經公證且超過5年者，丙可以要求乙房客搬遷", "若甲、乙之間的房屋租賃契約未定期限者，丙可主張隨時終止租賃契約，要求乙房客搬遷", "租期屆滿後，乙得向丙主張返還二個月的押租金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01109', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有一幅臺灣著名畫家之名畫，市值新臺幣 500 萬元，借給乙在畫展中展覽，並未委託乙出售。丙 觀賞該名畫，愛不釋手，不知該畫是乙向甲借的，於是向乙表示願出新臺幣 700 萬元請乙割愛，乙 就以新臺幣700萬元將該畫賣給丙，並以移轉所有權之意思交付給丙。下列敘述何者正確？', '["甲得請求丙返還該畫", "甲得請求乙新臺幣700萬元", "甲最多只能請求乙新臺幣500萬元", "甲最多只能請求乙新臺幣600萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01110', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與女秘書乙發生婚外情，甲與乙約定以繼續維繫婚外情為前提，贈與乙A屋一棟，一年後乙不欲 繼續維持不倫關係，A屋該如何處理？', '["A屋係以解除條件為前提的贈與契約，條件成就，贈與契約解除，A屋須返還給甲", "甲與乙之間的贈與契約係以維繫婚外情為前提，贈與契約內容違反公序良俗無效，A屋須返還給甲", "乙受贈A屋係屬不法原因而為給付者，甲事後不能請求返還A屋", "甲贈與乙A屋為無償行為，故贈與人甲可隨時撤銷該贈與契約，請求返還A屋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01111', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '18歲的甲騎機車上學途中撞傷騎腳踏車的乙。下列敘述何者正確？', '["甲未成年，所以不須負損害賠償之責", "由甲的法定代理人負損害賠償之責", "以甲行為時有意思能力為限，與其法定代理人連帶負損害賠償責任", "法定代理人如其監督並未疏懈，或縱加以相當之監督，而仍不免發生損害者，得主張免責"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01112', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲所有的A屋蓋在乙已登記的B地上18年。下列敘述何者正確？', '["乙可向甲主張B地的所有物返還請求權，請求甲拆屋還地", "已經超過15年，乙不可向甲主張B地的所有物返還請求權，請求甲拆屋還地", "甲可主張時效取得B地的所有權", "甲如為善意占有人，始得主張時效取得B地的所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01113', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲未將代理權授與給乙，乙卻以甲之代理人名義與善意之丙訂立買賣契約，甲不承認乙之無權代理 行為。下列敘述何者正確？', '["乙與丙簽訂之買賣契約，效力雖不及於甲，但在乙丙之間有效", "乙與丙簽訂之買賣契約，對甲丙、乙丙均無效，丙得請求乙損害賠償", "乙與丙簽訂之買賣契約，對甲丙、乙丙均無效，丙得請求甲損害賠償", "乙與丙簽訂之買賣契約，對甲丙、乙丙均有效，但丙得撤銷買賣契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
